import './ProgressBar.scss';

import type { DonutChartProps } from ':components/ProgressBar/ProgressBar.types';
import { classNames } from ':helpers/classnames';
import * as colors from '@beeline/design-tokens/js/tokens/globals/colors';
import React, { useRef } from 'react';

const DonutSection = ({ item, radius, startAngle, endAngle, onMouseMove, onMouseLeave }) => {
	const angleDiff = endAngle - startAngle;
	const isFullCircle = Math.abs(angleDiff) >= 359.99;

	const largeArcFlag = angleDiff <= 180 ? '0' : '1';
	const start = polarToCartesian(radius, radius, radius, endAngle);
	const end = polarToCartesian(radius, radius, radius, startAngle);

	const { color, label } = item;
	const [isHovered, setHovered] = React.useState(false);
	const colorToken = isHovered ? colors[`colorChart${color}Active`] : colors[`colorChart${color}`];

	let svgd;
	if (isFullCircle) {
		svgd = [`M ${radius} ${radius}`, `L ${radius} 0`, `A ${radius} ${radius} 0 1 1 ${radius - 0.01} 0`, 'Z'].join(' ');
	} else {
		svgd = [
			`M ${radius} ${radius}`,
			`L ${start.x} ${start.y}`,
			`A ${radius} ${radius} 0 ${largeArcFlag} 0 ${end.x} ${end.y}`,
			'Z',
		].join(' ');
	}

	const sectionRef = useRef<SVGPathElement | null>(null);
	return (
		<path
			ref={sectionRef}
			onMouseMove={event => {
				setHovered(true);
				onMouseMove?.(event, item, sectionRef);
			}}
			onMouseLeave={event => {
				setHovered(false);
				onMouseLeave?.(event, item, sectionRef);
			}}
			d={svgd}
			fill={colorToken}
			data-testid={`donut-section-${label}`}
		/>
	);
};

const polarToCartesian = (centerX, centerY, radius, angleInDegrees) => {
	const angleInRadians = ((angleInDegrees - 90) * Math.PI) / 180;
	return {
		x: centerX + radius * Math.cos(angleInRadians),
		y: centerY + radius * Math.sin(angleInRadians),
	};
};

export const DonutChart: React.FC<Omit<DonutChartProps, 'type'>> = ({
	values,
	height = 200,
	width = 200,
	maxValue = 100,
	innerElement,
	onMouseMove,
	onMouseLeave,
	innerRadius,
	className,
}) => {
	const calculatedValues =
		maxValue === 100
			? values
			: values.map(item => ({
					...item,
					value: (item.value / maxValue) * 100,
				}));
	const total = 100;
	const radius = Math.min(width, height) / 2;
	let cumulativeValue = 0;

	return (
		<div
			className={classNames('progressbar__donutchart', className)}
			data-testid="progressbar"
			role="progressbar"
			aria-valuemax={maxValue}
			aria-valuemin={0}
			aria-valuenow={calculatedValues.reduce((sum, i) => (sum += i.value), 0)}
		>
			<svg width={width} height={height} viewBox={`0 0 ${width} ${height}`}>
				<circle className="progressbar__donutchart__backgroundcircle" cx={radius} cy={radius} r={radius} />
				{calculatedValues.map((item, index) => {
					const startAngle = (cumulativeValue / total) * 360;
					cumulativeValue += item.value;
					const endAngle = (cumulativeValue / total) * 360;

					return (
						<DonutSection
							key={index}
							item={item}
							radius={radius}
							startAngle={startAngle}
							endAngle={endAngle}
							onMouseMove={onMouseMove}
							onMouseLeave={onMouseLeave}
						/>
					);
				})}
				<circle className="progressbar__donutchart__innerRadius" cx={radius} cy={radius} r={innerRadius} fill="white" />
			</svg>
			<div className="progressbar__donutchart__innerElement">{innerElement}</div>
		</div>
	);
};
